import React, { useState, useEffect } from 'react';
import { useAuth } from '../services/authService';
import { updateUser, uploadProfileImage } from '../services/userService';

const Profile = () => {
    const { user, login } = useAuth();
    const [formData, setFormData] = useState({
        firstName: user?.firstName || '',
        lastName: user?.lastName || '',
        email: user?.email || '',
    });
    const [loading, setLoading] = useState(false);
    const [imageLoading, setImageLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');
        setError('');
        try {
            const updatedUser = await updateUser(user.id, formData);
            setMessage('Profile updated successfully!');
            // Update auth context if it supports it, or just refresh?
            // Local login update might be needed.
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to update profile');
        } finally {
            setLoading(false);
        }
    };

    const handleImageUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        setImageLoading(true);
        try {
            await uploadProfileImage(user.id, file);
            setMessage('Profile picture updated!');
            window.location.reload(); // Quick way to refresh common UI
        } catch (err) {
            setError('Failed to upload image');
        } finally {
            setImageLoading(false);
        }
    };

    const profileImageUrl = user?.profileImage 
        ? `http://localhost:8081/api/users/${user.id}/profile-image` 
        : 'https://www.gravatar.com/avatar/00000000000000000000000000000000?d=mp&f=y';

    return (
        <div className="max-w-4xl mx-auto px-4 py-12">
            <h1 className="text-3xl font-extrabold text-white mb-8">My Profile</h1>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {/* Left: Avatar */}
                <div className="md:col-span-1">
                    <div className="glass-card p-6 text-center">
                        <div className="relative w-32 h-32 mx-auto rounded-full overflow-hidden border-4 border-indigo-500/30 mb-4 shadow-xl">
                            <img src={profileImageUrl} alt="Avatar" className="w-full h-full object-cover" />
                            {imageLoading && (
                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                                    <div className="animate-spin h-6 w-6 border-2 border-white border-t-transparent rounded-full" />
                                </div>
                            )}
                        </div>
                        <label className="btn-ghost text-xs cursor-pointer inline-block">
                            Change Picture
                            <input type="file" className="hidden" onChange={handleImageUpload} accept="image/*" />
                        </label>
                        <div className="mt-4">
                            <h2 className="text-xl font-bold text-white">{user?.username}</h2>
                            <p className="text-slate-500 text-sm">{user?.email}</p>
                        </div>
                    </div>
                </div>

                {/* Right: Form */}
                <div className="md:col-span-2">
                    <div className="glass-card p-8">
                        {message && <div className="alert-success mb-6">{message}</div>}
                        {error && <div className="alert-error mb-6">{error}</div>}

                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-semibold text-slate-300 mb-2">First Name</label>
                                    <input type="text" name="firstName" value={formData.firstName} onChange={handleChange} className="input-field" />
                                </div>
                                <div>
                                    <label className="block text-sm font-semibold text-slate-300 mb-2">Last Name</label>
                                    <input type="text" name="lastName" value={formData.lastName} onChange={handleChange} className="input-field" />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-slate-300 mb-2">Email Address</label>
                                <input type="email" name="email" value={formData.email} onChange={handleChange} className="input-field" />
                            </div>
                            <div className="pt-4 border-t border-white/5">
                                <button type="submit" disabled={loading} className="btn-primary">
                                    {loading ? 'Saving...' : 'Save Changes'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Profile;
